    drag_paths = plan.get("drag_paths", []) if isinstance(plan, dict) else []  # 新增代码+Task8Maturity：读取拖拽路径集合；如果没有这一行，后续无法检查是否真的有鼠标路径。
    first_path = drag_paths[0] if isinstance(drag_paths, list) and drag_paths else {}  # 新增代码+Task8Maturity：取第一条路径作为事件展开样本；如果没有这一行，primitive 只证明有计划而不证明可展开。
    first_points = first_path.get("points", []) if isinstance(first_path, dict) else []  # 新增代码+Task8Maturity：读取第一条路径点位；如果没有这一行，底层事件展开没有输入。
    sample_events = expand_drag_path_to_low_level_events(first_points)  # 新增代码+Task8Maturity：把拖拽路径展开成鼠标 move/down/up 事件；如果没有这一行，矩阵无法证明动作层可消费 primitive。
    report = dict(plan) if isinstance(plan, dict) else {"passed": False}  # 新增代码+Task8Maturity：复制 primitive 报告；如果没有这一行，后续附加字段会污染原始对象或缺少兜底。
    report["sample_low_level_event_count"] = len(sample_events)  # 新增代码+Task8Maturity：记录样本路径展开出的底层事件数量；如果没有这一行，测试无法确认 primitive 不只是静态坐标。
