def _computer_use_full_matrix_learning_agent_source_report() -> dict[str, Any]:  # 新增代码+ModelLoopMaturityMatrix：函数段开始，用 AST 读取 LearningAgent 当前源码结构；如果没有这个函数，矩阵会继续靠旧记忆判断主循环设计。
    agent_path = Path(__file__).resolve().parents[1] / "core" / "agent.py"  # 新增代码+ModelLoopMaturityMatrix：定位当前项目里的 core/agent.py；如果没有这一行，源码自检可能读错文件。
    try:  # 新增代码+ModelLoopMaturityMatrix：尝试读取当前源码文本；如果没有这一行，文件读取异常会直接中断 maturity 命令。
        source_text = agent_path.read_text(encoding="utf-8")  # 新增代码+ModelLoopMaturityMatrix：用 UTF-8 读取源码；如果没有这一行，AST 无法解析当前实现。
        module_ast = ast.parse(source_text)  # 新增代码+ModelLoopMaturityMatrix：把源码解析成 AST；如果没有这一行，只能做脆弱字符串匹配。
    except (OSError, SyntaxError) as error:  # 新增代码+ModelLoopMaturityMatrix：捕获文件读取或语法解析失败；如果没有这一行，坏源码会让用户看不到结构化失败原因。
        return {"passed": False, "source_path": str(agent_path), "error": str(error)}  # 新增代码+ModelLoopMaturityMatrix：返回失败报告而不是抛异常；如果没有这一行，maturity 命令不可用。
    class_node = next((node for node in module_ast.body if isinstance(node, ast.ClassDef) and node.name == "LearningAgent"), None)  # 新增代码+ModelLoopMaturityMatrix：定位 LearningAgent 类；如果没有这一行，报告无法证明主循环属于当前 agent。
    if class_node is None:  # 新增代码+ModelLoopMaturityMatrix：处理类不存在的异常源码形态；如果没有这一行，后续访问 body 会崩溃。
        return {"passed": False, "source_path": str(agent_path), "reason": "learning_agent_class_not_found"}  # 新增代码+ModelLoopMaturityMatrix：返回可读失败原因；如果没有这一行，排查会缺少定位信息。
    method_nodes = {node.name: node for node in class_node.body if isinstance(node, ast.FunctionDef)}  # 新增代码+ModelLoopMaturityMatrix：收集 LearningAgent 的普通方法；如果没有这一行，后续无法按方法名做架构检查。
    run_node = method_nodes.get("run")  # 新增代码+ModelLoopMaturityMatrix：读取 run 主入口；如果没有这一行，无法确认用户输入是否先交给模型主循环。
    runtime_node = method_nodes.get("_desktop_task_runtime_for_current_run")  # 新增代码+ModelLoopMaturityMatrix：读取默认桌面 runtime 构造方法；如果没有这一行，无法确认生产路径是否启用 Paint 专用桥。
    preclassifier_calls = [call for call in ast.walk(run_node) if isinstance(call, ast.Call) and _computer_use_full_matrix_call_name(call) == "_desktop_task_runtime_answer_from_prompt"] if run_node is not None else []  # 新增代码+ModelLoopMaturityMatrix：检查 run() 是否调用旧 Python 预分类器；如果没有这一行，语义规划是否抢跑无法由源码证明。
    required_image_methods = {"_tool_result_messages_to_dicts", "_computer_use_image_message_from_tool_output", "_computer_use_image_blocks_from_tool_output", "_computer_use_model_image_payload"}  # 新增代码+ModelLoopMaturityMatrix：列出截图回流所需方法；如果没有这一行，模型可见图片能力没有清晰验收边界。
    image_methods_present = required_image_methods.issubset(set(method_nodes))  # 新增代码+ModelLoopMaturityMatrix：检查图片回流方法是否都在 LearningAgent 上；如果没有这一行，截图是否能进入模型仍会靠猜。
    adapter_calls = [call for call in ast.walk(runtime_node) if isinstance(call, ast.Call) and _computer_use_full_matrix_call_name(call) == "UniversalDesktopExecutionLoopAdapter"] if runtime_node is not None else []  # 新增代码+ModelLoopMaturityMatrix：检查默认 runtime 是否构造通用桌面 adapter；如果没有这一行，生产路径可能仍停在旧桥。
    paint_bridge_values = [_computer_use_full_matrix_ast_bool_value(keyword.value) for call in adapter_calls for keyword in call.keywords if keyword.arg == "enable_supported_paint_drawing"]  # 新增代码+ModelLoopMaturityMatrix：读取是否显式打开 Paint 专用绘图桥；如果没有这一行，旧桥是否进入默认生产路径无法证明。
